/**
 * Reconnecting WebSocket with automatic retry logic.
 *
 * Features:
 * - **Drop-in replacement** â€” standard `WebSocket` API, swap one line
 * - **Auto-reconnection** â€” configurable retries and delay strategy
 * - **Message buffering** â€” `send()` queues data while offline, flushes on reconnect
 * - **Persistent listeners** â€” `addEventListener` and `on*` handlers survive reconnections
 * - **Dynamic URL & protocols** â€” resolve fresh values on each reconnection
 * - **Zero dependencies** â€” works in Node.js, Deno, Bun, and browsers
 *
 * @example
 * ```ts
 * import { ReconnectingWebSocket } from "@nktkas/rews";
 *
 * const ws = new ReconnectingWebSocket("wss://api.example.com/ws", {
 *   maxRetries: 10,
 *   reconnectionDelay: (attempt) => Math.min(2 ** attempt * 100, 5_000),
 * });
 *
 * ws.addEventListener("open", () => console.log("connected")); // fires on every reconnect
 * ws.addEventListener("message", (event) => console.log(event.data));
 *
 * ws.send("hello"); // buffered while offline, sent once connected
 * ```
 *
 * @module
 */
